//! Auto-generated by the spec-word-compliance workflow for area
//! "Run character spacing, kerning, scaling, position, and fit".
//!
//! Each `#[test]` encodes a Word-consumption rule from ECMA-376 / MS-OI29500
//! about run-level character-spacing / kerning / fitText / eastAsianLayout
//! directives. These are all LAYOUT-ONLY / render-only properties: per the
//! spec they never participate in the run's character stream. The tests assert
//! on the READ surface (accept/reject text) and opens-clean, which is the
//! correct consumption surface (see CLAUDE.md "consumption vs. save": these are
//! NOT serializer-emission claims, so no xml* assertions appear here).
//!
//! A FAILING assertion is a REAL Word-compliance gap in stemma — it means
//! stemma either mutated the text stream for a layout directive or refused a
//! schema-valid package Word opens clean. Do NOT weaken a failing assertion to
//! make it pass; a fail is a finding.

use stemma::api::{Document, validate};

// ─── Prelude / helpers ───────────────────────────────────────────────────────

/// Build a minimal valid `.docx` whose `word/document.xml` body is `body_xml`
/// (already including any trailing `<w:sectPr/>`). `extra_parts` are extra
/// package parts as `(part_path, xml)` — e.g. `("word/styles.xml", "...")` —
/// for which a `[Content_Types].xml` override and a `document.xml.rels`
/// relationship are synthesized.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    fn override_for(part: &str) -> &'static str {
        if part.ends_with("styles.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
        } else if part.ends_with("numbering.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
        } else {
            // Unknown extra part: fail loud rather than emit a wrong content type.
            panic!("make_docx: no content-type mapping for extra part {part:?}");
        }
    }
    fn rel_type_for(part: &str) -> &'static str {
        if part.ends_with("styles.xml") {
            "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles"
        } else if part.ends_with("numbering.xml") {
            "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering"
        } else {
            panic!("make_docx: no relationship type for extra part {part:?}");
        }
    }

    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    let mut doc_rels_entries = String::new();
    for (i, (part, _)) in extra_parts.iter().enumerate() {
        let part_name = if part.starts_with('/') {
            part.to_string()
        } else {
            format!("/{part}")
        };
        overrides.push_str(&format!(
            r#"<Override PartName="{part_name}" ContentType="{}"/>"#,
            override_for(part)
        ));
        let target = part.strip_prefix("word/").unwrap_or(part);
        doc_rels_entries.push_str(&format!(
            r#"<Relationship Id="rIdX{n}" Type="{ty}" Target="{target}"/>"#,
            n = i + 1,
            ty = rel_type_for(part),
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rels_entries}</Relationships>"#
    );

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            zip.start_file(*part, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip and return `word/document.xml` as a `String`.
#[allow(dead_code)]
fn document_xml_of(docx: &[u8]) -> String {
    let archive = stemma::docx::DocxArchive::read(docx).expect("read docx archive");
    let bytes = archive
        .get("word/document.xml")
        .expect("word/document.xml present");
    String::from_utf8_lossy(bytes).into_owned()
}

/// Parse, serialize with default export options, and return the resulting
/// `word/document.xml`. NOTE: stemma round-trips untouched content verbatim, so
/// this reflects stemma's preservation contract, not Word normalization. None
/// of the specs in this file use xml* expectations (they are all consumption /
/// opens-clean rules), so this helper is provided for completeness only.
#[allow(dead_code)]
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc
        .serialize(&stemma::ExportOptions::default())
        .expect("serialize");
    document_xml_of(&out)
}

/// Assert the package opens clean (validator reports no errors).
fn assert_opens_clean(bytes: &[u8], ctx: &str) {
    let report = validate(bytes);
    assert!(
        report.ok,
        "{ctx} — expected the package to open clean (no validation errors), \
         but the validator reported: {issues:?}",
        issues = report.issues
    );
}

fn accept_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_accepted()
        .expect("accept-all")
        .to_text()
        .trim()
        .to_string()
}

fn reject_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_rejected()
        .expect("reject-all")
        .to_text()
        .trim()
        .to_string()
}

// ─── Tests ───────────────────────────────────────────────────────────────────

#[test]
fn ea_layout_combinebrackets_ignored_without_combine_text_unchanged() {
    let body = r#"<w:p><w:r><w:rPr><w:eastAsianLayout w:combineBrackets="curly"/></w:rPr><w:t>bracketsalone</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b),
        "bracketsalone",
        "ISO 29500-1 §17.3.2.10 / §17.18.8 (ST_CombineBrackets): combineBrackets is a \
         display-only bracket-style directive (ignored entirely when combine is absent); \
         it must inject no glyphs into the text stream, so accept-all text equals the \
         authored characters"
    );
    assert_eq!(
        reject_text(&b),
        "bracketsalone",
        "ISO 29500-1 §17.3.2.10: layout decoration never participates in the text \
         stream, so reject-all leaves the authored characters unchanged"
    );
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.3.2.10 / §17.18.8 (ST_CombineBrackets): combineBrackets alone \
         is schema-valid and Word opens it without repair",
    );
}

#[test]
fn ea_layout_vertcompress_ignored_without_vert_text_unchanged() {
    let body = r#"<w:p><w:r><w:rPr><w:eastAsianLayout w:vertCompress="true"/></w:rPr><w:t>compressme</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b),
        "compressme",
        "ISO 29500-1 §17.3.2.10 / §22.9.2.7 (ST_OnOff): vertCompress is a render-only \
         compression hint (ignored without vert); accept-all text equals the authored \
         characters"
    );
    assert_eq!(
        reject_text(&b),
        "compressme",
        "ISO 29500-1 §17.3.2.10: a compression hint never participates in the text \
         stream, so reject-all leaves the authored characters unchanged"
    );
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.3.2.10 / §22.9.2.7 (ST_OnOff): vertCompress alone is \
         schema-valid and Word opens it without repair",
    );
}

#[test]
fn fittext_id_render_only_text_unchanged_noncontiguous() {
    let body = r#"<w:p><w:r><w:rPr><w:fitText w:id="99" w:val="1440"/></w:rPr><w:t>alpha</w:t></w:r><w:r><w:t>gap</w:t></w:r><w:r><w:rPr><w:fitText w:id="99" w:val="1440"/></w:rPr><w:t>omega</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b),
        "alphagapomega",
        "ISO 29500-1 §17.3.2.14 / §17.18.10: fitText is a display-time width directive; \
         non-contiguous same-id runs are merely unlinked for layout (the id is ignored), \
         so accept-all preserves the concatenated authored text exactly"
    );
    assert_eq!(
        reject_text(&b),
        "alphagapomega",
        "ISO 29500-1 §17.3.2.14: a manual-run-width directive never participates in the \
         text stream, so reject-all leaves all authored characters unchanged"
    );
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.3.2.14: two fitText runs with a shared id separated by a plain \
         run is schema-valid and Word opens it without repair",
    );
}

#[test]
fn spacing_with_fittext_text_unchanged_opens_clean() {
    let body = r#"<w:p><w:r><w:rPr><w:spacing w:val="200"/><w:fitText w:id="50" w:val="720"/></w:rPr><w:t>conflictpair</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b),
        "conflictpair",
        "ISO 29500-1 §17.3.2.35 / §17.3.2.14 / MS-OI29500 §2.1.96: spacing and fitText \
         are both layout-only (Word ignores spacing when fitText is present); neither \
         edits text, so accept-all yields the authored characters"
    );
    assert_eq!(
        reject_text(&b),
        "conflictpair",
        "MS-OI29500 §2.1.96: the spacing-vs-fitText conflict is resolved on layout only, \
         so reject-all leaves the authored characters unchanged"
    );
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.3.2.35 / §17.3.2.14: a run carrying both spacing and fitText is \
         schema-valid and Word opens it without repair",
    );
}

#[test]
fn kern_below_sz_threshold_text_unchanged_opens_clean() {
    let body = r#"<w:p><w:r><w:rPr><w:kern w:val="28"/><w:sz w:val="22"/></w:rPr><w:t>belowthreshold</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b),
        "belowthreshold",
        "ISO 29500-1 §17.3.2.19 / §17.3.2.38: kern (28 half-pts) exceeds sz (22 half-pts) \
         so Word performs no kerning; kerning is render-only either way, so accept-all \
         yields the authored characters"
    );
    assert_eq!(
        reject_text(&b),
        "belowthreshold",
        "ISO 29500-1 §17.3.2.19: kerning suppression is a layout decision, so reject-all \
         leaves the authored characters unchanged"
    );
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.3.2.19 / §17.18.42 (ST_HpsMeasure): a run with kern threshold \
         above its sz is schema-valid and Word opens it without repair",
    );
}

#[test]
fn fittext_with_spacing_and_eastasianlayout_layout_only_text_unchanged() {
    let body = r#"<w:p><w:r><w:rPr><w:spacing w:val="40"/><w:fitText w:id="50" w:val="720"/><w:eastAsianLayout w:id="1" w:combine="on"/></w:rPr><w:t>fit me</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.3.2.14 / §17.3.2.35 / §17.3.2.10 / MS-OI29500 §2.1.78 / §2.1.75: \
         fitText, spacing and eastAsianLayout are all valid CT_RPr children that may \
         co-occur; Word resolves the conflict at layout and opens the file without repair",
    );
    assert_eq!(
        accept_text(&b),
        "fit me",
        "MS-OI29500 §2.1.78: all three are render-only directives; none mutates run \
         content, so accept-all reproduces the authored text exactly"
    );
    assert_eq!(
        reject_text(&b),
        "fit me",
        "ISO 29500-1 §17.3.2.14: there is no tracked change; reject-all is identity over \
         the layout-only run, yielding the authored text"
    );
}

#[test]
fn eastasianlayout_combine_ignores_vert_layout_only_text_unchanged() {
    let body = r#"<w:p><w:r><w:rPr><w:eastAsianLayout w:id="1" w:combine="on" w:vert="on"/></w:rPr><w:t>two lines</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.3.2.10 / §17.18.8 / MS-OI29500 §2.1.75: combine and vert are \
         both valid ST_OnOff attributes of CT_EastAsianLayout; Word resolves the conflict \
         at layout and opens without repair",
    );
    assert_eq!(
        accept_text(&b),
        "two lines",
        "MS-OI29500 §2.1.75: eastAsianLayout is render-only; the combine/vert conflict \
         (vert ignored) does not change run content, so accept-all yields the authored text"
    );
    assert_eq!(
        reject_text(&b),
        "two lines",
        "ISO 29500-1 §17.3.2.10: no tracked change is present; reject-all is identity, \
         yielding the authored text"
    );
}

#[test]
fn eastasianlayout_vertcompress_ignored_layout_only_text_unchanged() {
    let body = r#"<w:p><w:r><w:rPr><w:eastAsianLayout w:id="2" w:vert="on" w:vertCompress="on"/></w:rPr><w:t>vertical</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.3.2.10 / §22.9.2.7 / MS-OI29500 §2.1.75: vert and vertCompress \
         are valid ST_OnOff attributes; Word ignores vertCompress at layout but opens the \
         file without repair",
    );
    assert_eq!(
        accept_text(&b),
        "vertical",
        "MS-OI29500 §2.1.75: eastAsianLayout (vert/vertCompress) is render-only; ignoring \
         vertCompress cannot change run content, so accept-all yields the authored text"
    );
    assert_eq!(
        reject_text(&b),
        "vertical",
        "ISO 29500-1 §17.3.2.10: no tracked change; reject-all is identity, yielding the \
         authored text"
    );
}

#[test]
fn fittext_omitted_id_links_contiguous_runs_layout_only_text_unchanged() {
    let body = r#"<w:p><w:r><w:rPr><w:fitText w:val="720"/></w:rPr><w:t>fit </w:t></w:r><w:r><w:rPr><w:fitText w:val="720"/></w:rPr><w:t>this</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.3.2.14 / §17.18.10 / MS-OI29500 §2.1.78: w:fitText with an \
         omitted id and a valid w:val is well-formed CT_FitText; Word fills the missing \
         id with 0 and opens the file without repair",
    );
    assert_eq!(
        accept_text(&b),
        "fit this",
        "MS-OI29500 §2.1.78: fitText only fixes display width; the omitted-id linking is \
         a layout grouping that does not alter run content, so accept-all reproduces both \
         runs' authored text"
    );
    assert_eq!(
        reject_text(&b),
        "fit this",
        "ISO 29500-1 §17.3.2.14: no tracked change; reject-all is identity over the two \
         layout-only runs, yielding the authored concatenation"
    );
}

#[test]
fn kern_at_word_max_3277_with_sz_opens_clean_text_unchanged() {
    let body = r#"<w:p><w:r><w:rPr><w:kern w:val="3277"/><w:sz w:val="24"/></w:rPr><w:t>kerned text</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.3.2.19 / §17.18.42 / MS-OI29500 §2.1.83: kern=3277 is the \
         inclusive maximum of Word's unsignedInt 0..3277 domain; the markup is in-range \
         and Word opens it without repair",
    );
    assert_eq!(
        accept_text(&b),
        "kerned text",
        "MS-OI29500 §2.1.83: kern is a render-only kerning threshold; it does not mutate \
         run content, so accept-all yields the authored text"
    );
    assert_eq!(
        reject_text(&b),
        "kerned text",
        "ISO 29500-1 §17.3.2.19: no tracked change; reject-all is identity, yielding the \
         authored text"
    );
}

#[test]
fn spacing_ignored_when_fittext_present_is_render_only_text_unchanged() {
    let body = r#"<w:p><w:r><w:rPr><w:spacing w:val="40"/><w:fitText w:id="7" w:val="720"/></w:rPr><w:t>fitme</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b),
        "fitme",
        "MS-OI29500 §2.1.96 / ISO 29500-1 §17.3.2.35 / §17.3.2.14: fitText (which wins \
         over spacing) and spacing are both render-only; the run text is unaffected, so \
         accept-all yields the authored text verbatim"
    );
    assert_eq!(
        reject_text(&b),
        "fitme",
        "MS-OI29500 §2.1.96: there is no tracked change; spacing/fitText never alter \
         character data, so reject-all equals the authored text"
    );
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.3.2.35 / §17.3.2.14: spacing+fitText together is schema-valid \
         CT_RPr content; Word opens it without repair",
    );
}

#[test]
fn direct_spacing_overrides_style_spacing_last_writer_wins_non_toggle() {
    let body = r#"<w:p><w:pPr><w:rPr><w:rStyle w:val="Wide"/></w:rPr></w:pPr><w:r><w:rPr><w:rStyle w:val="Wide"/><w:spacing w:val="-20"/></w:rPr><w:t>kerned</w:t></w:r></w:p><w:sectPr/>"#;
    let styles = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:style w:type="character" w:styleId="Wide"><w:name w:val="Wide"/><w:rPr><w:spacing w:val="60"/></w:rPr></w:style></w:styles>"#;
    let b = make_docx(body, &[("word/styles.xml", styles)]);

    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.7.3 / §17.7.1 / §17.3.2.35: a style spacing plus a direct \
         spacing on the same run is valid markup; Word resolves it (direct wins) at \
         layout and opens the file without repair",
    );
    assert_eq!(
        accept_text(&b),
        "kerned",
        "ISO 29500-1 §17.7.3: spacing is non-toggle (the toggle list is closed and \
         excludes spacing), so direct (last in resolution order) wins; it is render-only \
         and there is no tracked change, so accept-all equals the authored text"
    );
}
